// Parse Slack interaction payload (block_actions)
// Input: raw_payload from Route by Payload Type (already parsed)
const parsedPayload = $input.first().json.raw_payload;

const action = parsedPayload.actions?.[0];
const user = parsedPayload.user;
const channel = parsedPayload.channel;
const blocks = parsedPayload.message?.blocks || [];

// Helper: extract value from mrkdwn fields like "*Label:*\nValue"
function extractFromField(blocks, label) {
  for (const block of blocks) {
    if (block.type === 'section' && block.fields) {
      for (const field of block.fields) {
        if (field.text?.includes(label)) {
          const parts = field.text.split('\n');
          return parts.length > 1 ? parts[1].trim() : null;
        }
      }
    }
  }
  return null;
}

// Helper: extract text inside ``` code blocks ``` from a section
function extractSectionText(blocks, header) {
  for (const block of blocks) {
    if (block.type === 'section' && block.text?.text?.includes(header)) {
      const match = block.text.text.match(/```([\s\S]*?)```/);
      return match ? match[1].trim() : null;
    }
  }
  return null;
}

// Strip Slack's auto-formatted links back to plain URLs
function cleanSlackLinks(text) {
  if (!text) return text;
  text = text.replace(/<a[^>]*href="([^"]*)"[^>]*>[^<]*<\/a>/g, '$1');
  text = text.replace(/<(https?:\/\/[^|>]+)\|[^>]+>/g, '$1');
  text = text.replace(/<(https?:\/\/[^>]+)>/g, '$1');
  return text;
}

return {
  json: {
    action_id: action?.action_id,
    action_value: action?.value,
    trigger_id: parsedPayload.trigger_id,
    slack_channel_id: channel?.id,
    slack_channel_name: channel?.name,
    slack_user_id: user?.id,
    slack_user_name: user?.name || user?.username,
    contact_name: extractFromField(blocks, '*Contact name:*') || 'Unknown',
    contact_number: extractFromField(blocks, '*Number:*'),
    restaurant_name: extractFromField(blocks, '*Restaurant:*'),
    country: extractFromField(blocks, '*Country:*'),
    lead_message: cleanSlackLinks(extractSectionText(blocks, "*Prospect's Reply:*")),
    ai_generated_response: cleanSlackLinks(extractSectionText(blocks, '*Agent Generated Response:*')),
    response_url: parsedPayload.response_url,
    original_message_ts: parsedPayload.message?.ts,
  }
};

